-        SigEntry::add_entry(_sig_cc_ro, T_METADATA, nullptr, offset);
+        if (!skipping_inline_recv) {
+          if (!receiver_handled && _has_inline_recv && value_object_count == 0) {
+            SigEntry::add_entry(_sig_cc_ro, T_OBJECT);
+            skipping_inline_recv = true;
